#!/usr/bin/env python3
import base64, os, sys

if not os.path.exists("src/app"):
    print("ERREUR: Lance ce script depuis ~/Desktop/pandasnack")
    sys.exit(1)

FILES = {
    "src/app/commander/CommanderClient.tsx": "",
    "src/app/mes-commandes/MesCommandesClient.tsx": "",
    "src/app/mes-commandes/page.tsx": "",
    "src/app/api/checkout/route.ts": "",
    "src/app/api/save-order/route.ts": "",
    "src/app/api/order-item/route.ts": "",
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    data = base64.b64decode(b64).decode('utf-8')
    with open(path, 'w') as f:
        f.write(data)
    print(f"  ✅ {path} ({len(data)} bytes)")

print(f"\n🎉 {len(FILES)} fichier(s) écrit(s). git add . && git commit && git push")